# scripts/validate_prompt_yaml.py
import sys, yaml, re
from pathlib import Path

VALID_MODELS = {
    "claude-haiku-4-5-20251001",
    "claude-sonnet-5",
    "claude-opus-4-8",
}
REQUIRED_FIELDS = {"version", "model", "max_tokens", "temperature", "system",
                   "user_template", "template_vars", "eval_suite"}

def validate(path: str):
    doc = yaml.safe_load(Path(path).read_text())
    errors = []

    missing = REQUIRED_FIELDS - doc.keys()
    if missing:
        errors.append(f"missing required fields: {missing}")

    if doc.get("model") not in VALID_MODELS:
        errors.append(f"unknown model: {doc.get('model')!r}")

    if not re.match(r"^\d+\.\d+\.\d+$", str(doc.get("version", ""))):
        errors.append(f"version must be semver: {doc.get('version')!r}")

    temp = doc.get("temperature", -1)
    if not (0.0 <= float(temp) <= 1.0):
        errors.append(f"temperature out of range: {temp}")

    max_tok = doc.get("max_tokens", 0)
    if not (1 <= int(max_tok) <= 32000):
        errors.append(f"max_tokens out of range: {max_tok}")

    for var in doc.get("template_vars", []):
        if "{{ " + var + " }}" not in doc.get("user_template", ""):
            errors.append(f"template_var '{var}' not used in user_template")

    if errors:
        for e in errors: print(f"ERROR: {e}")
        sys.exit(1)
    print("prompt.yaml valid")

validate(sys.argv[1])
